cat <<'EOF' > csv-parser.ts
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, any>) => boolean) => Record<string, any>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<any, Record<string, any>[]>;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';

function coerceValue(raw: string): any {
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }
  const numericPattern = /^[+-]?(?:\d+\.?\d*|\.\d+)$/;
  if (numericPattern.test(trimmed)) {
    const parsed = Number(trimmed);
    if (!Number.isNaN(parsed)) {
      return parsed;
    }
  }
  return trimmed;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  if (!input) {
    const emptyResult: CSVResult = {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => NaN,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quoteChar = options.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator;

  const rows: string[][] = [];
  const rowNumbers: number[] = [];
  let currentRow: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let rowNumber = 1;
  let lastWasLineBreak = false;

  const detectLineBreak = (index: number): { length: number; isLineBreak: boolean } => {
    if (lineSeparator) {
      if (input.startsWith(lineSeparator, index)) {
        return { length: lineSeparator.length, isLineBreak: true };
      }
      return { length: 0, isLineBreak: false };
    }
    const ch = input[index];
    if (ch === '\r') {
      if (input[index + 1] === '\n') {
        return { length: 2, isLineBreak: true };
      }
      return { length: 1, isLineBreak: true };
    }
    if (ch === '\n') {
      return { length: 1, isLineBreak: true };
    }
    return { length: 0, isLineBreak: false };
  };

  const finalizeRow = () => {
    currentRow.push(currentField);
    currentField = '';
    rows.push(currentRow);
    rowNumbers.push(rowNumber);
    currentRow = [];
    rowNumber += 1;
  };

  let i = 0;
  while (i < input.length) {
    const ch = input[i];
    if (ch === quoteChar) {
      if (inQuotes && input[i + 1] === quoteChar) {
        currentField += quoteChar;
        i += 2;
        lastWasLineBreak = false;
        continue;
      }
      inQuotes = !inQuotes;
      i += 1;
      lastWasLineBreak = false;
      continue;
    }

    if (!inQuotes) {
      const { isLineBreak, length } = detectLineBreak(i);
      if (isLineBreak) {
        finalizeRow();
        lastWasLineBreak = true;
        i += length;
        continue;
      }
      if (ch === delimiter) {
        currentRow.push(currentField);
        currentField = '';
        i += 1;
        lastWasLineBreak = false;
        continue;
      }
    }

    currentField += ch;
    lastWasLineBreak = false;
    i += 1;
  }

  if (currentField !== '' || currentRow.length > 0 || !lastWasLineBreak) {
    finalizeRow();
  }

  if (rows.length === 0) {
    const emptyResult: CSVResult = {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => NaN,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const headers = rows[0].map((value) => value ?? '');
  const dataRows = rows.slice(1);
  const dataRowNumbers = rowNumbers.slice(1);
  const normalizedRows: Record<string, any>[] = [];
  const errors: CSVError[] = [];

  for (let idx = 0; idx < dataRows.length; idx += 1) {
    const row = dataRows[idx];
    const expected = headers.length;
    const actual = row.length;
    const rowNum = dataRowNumbers[idx];
    if (actual !== expected) {
      errors.push({
        row: rowNum,
        message: `Expected ${expected} fields but got ${actual}`,
      });
    }
    const record: Record<string, any> = {};
    for (let h = 0; h < expected; h += 1) {
      const header = headers[h];
      const rawValue = row[h] ?? '';
      record[header] = coerceValue(rawValue);
    }
    normalizedRows.push(record);
  }

  const result: CSVResult = {
    rows: normalizedRows,
    headers,
    errors,
    filter: (predicate) => normalizedRows.filter(predicate),
    sum: (column: string) => {
      return normalizedRows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average: (column: string) => {
      let total = 0;
      let count = 0;
      normalizedRows.forEach((row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? NaN : total / count;
    },
    count: () => normalizedRows.length,
    groupBy: (column: string) => {
      const map = new Map<any, Record<string, any>[]>();
      normalizedRows.forEach((row) => {
        const key = row[column];
        const bucket = map.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          map.set(key, [row]);
        }
      });
      return map;
    },
  };

  return result;
}
