cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string): void {
  if (!condition) {
    throw new Error(message ?? 'Assertion failed');
  }
}

function arraysEqual(a: any[], b: any[]): boolean {
  if (a.length !== b.length) return false;
  return a.every((value, index) => {
    const other = b[index];
    if (Array.isArray(value) && Array.isArray(other)) {
      return arraysEqual(value, other);
    }
    if (value && typeof value === 'object' && other && typeof other === 'object') {
      return Object.keys(value).length === Object.keys(other).length &&
        Object.keys(value).every((key) => value[key] === other[key]);
    }
    return value === other;
  });
}

function runTests(): void {
  // Basic parsing
  const basic = parseCSV('name,age\nAlice,30\nBob,25');
  assert(arraysEqual(basic.headers, ['name', 'age']), 'Headers mismatch for basic parsing');
  assert(basic.rows.length === 2, 'Expected two rows for basic parsing');
  assert(basic.rows[0].name === 'Alice' && basic.rows[0].age === 30, 'Row 1 mismatch');
  assert(basic.rows[1].name === 'Bob' && basic.rows[1].age === 25, 'Row 2 mismatch');
  assert(basic.count() === 2, 'Count should be 2');

  // Quoted fields with commas
  const quoted = parseCSV('id,notes\n1,"hello, world"\n2,"another, test"');
  assert(quoted.rows[0].notes === 'hello, world', 'Quoted field with comma failed');
  assert(quoted.rows[1].notes === 'another, test', 'Second quoted field failed');

  // Escaped quotes
  const escaped = parseCSV('text\n"She said ""hi"""');
  assert(escaped.rows[0].text === 'She said "hi"', 'Escaped quote parsing failed');

  // Custom delimiter
  const custom = parseCSV('id|value\n1|foo\n2|bar', { delimiter: '|' });
  assert(custom.rows[0].value === 'foo', 'Custom delimiter parse failed');
  assert(custom.rows[1].value === 'bar', 'Custom delimiter parse second row failed');

  // Type coercion
  const typeSample = parseCSV('value\n123\n45.6\nTRUE\nfalse\nnull\nNULL\n\ntext\n  0.5  \n+7\n-.3\nNaN');
  const typeValues = typeSample.rows.map((row) => row.value);
  const expectedTypes = [123, 45.6, true, false, null, null, null, 'text', 0.5, 7, -0.3, 'NaN'];
  assert(arraysEqual(typeValues, expectedTypes), 'Type coercion values mismatch');

  // Malformed row detection
  const malformed = parseCSV('id,name\n1,Alice\n2\n3,Bob,extra');
  assert(malformed.errors.length === 2, 'Expected two errors for malformed rows');
  assert(malformed.errors[0].row === 3, 'Malformed error row number incorrect (missing column)');
  assert(malformed.errors[1].row === 4, 'Malformed error row number incorrect (extra column)');

  // Filtering
  const filterSample = parseCSV('name,age\nJan,20\nJoe,35\nPam,18');
  const adults = filterSample.filter((row) => row.age >= 21);
  assert(adults.length === 1 && adults[0].name === 'Joe', 'Filter failed to capture correct rows');

  // Aggregation methods
  const agg = parseCSV('group,value\nA,10\nA,20\nB,5\nC,notnum');
  assert(agg.sum('value') === 35, 'Sum aggregation incorrect');
  const average = agg.average('value');
  assert(!Number.isNaN(average) && Math.abs(average - 11.666666666666666) < 1e-9, 'Average aggregation incorrect');
  assert(agg.count() === 4, 'Count aggregation incorrect');
  const groups = agg.groupBy('group');
  assert(groups.size === 3, 'GroupBy bucket count wrong');
  assert(groups.get('A')?.length === 2, 'GroupBy bucket sizes incorrect for group A');
  assert(groups.get('C')?.length === 1, 'GroupBy bucket sizes incorrect for group C');

  // Edge cases
  const empty = parseCSV('');
  assert(empty.headers.length === 0, 'Empty input should have no headers');
  assert(empty.rows.length === 0, 'Empty input should have no rows');
  assert(empty.count() === 0, 'Count should be zero for empty input');

  const singleCol = parseCSV('value\nonly');
  assert(singleCol.headers[0] === 'value', 'Single column header mismatch');
  assert(singleCol.rows[0].value === 'only', 'Single column value mismatch');

  const headerOnly = parseCSV('a,b,c');
  assert(headerOnly.rows.length === 0, 'Header only input should have zero rows');

  const largeField = parseCSV('data\n"' + 'x'.repeat(20000) + '"');
  assert(largeField.rows[0].data.length === 20000, 'Large field length mismatch');
  assert(largeField.rows[0].data.startsWith('x') && largeField.rows[0].data.endsWith('x'), 'Large field content mismatch');

  console.log('All csv-parser tests passed.');
}

runTests();
